import { readFileSync } from "node:fs";
import { describe, expect, it } from "vitest";

// File-content inspection (no JSX runtime needed). The behavioural test for
// this page is "open localhost:3000 in a browser and submit the form" — see
// REPORT.md for the run record.
const SRC = readFileSync("./app/page.tsx", "utf-8");

describe("app/page.tsx (landing page UI)", () => {
  it("opens with the \"use client\" directive (required for the form's useState)", () => {
    expect(SRC.startsWith('"use client";')).toBe(true);
  });

  it("default-exports a HomePage React function component", () => {
    expect(SRC).toMatch(/export default function HomePage/);
  });

  it("posts to /api/signup with the source field per the CTO contract", () => {
    expect(SRC).toMatch(/fetch\("\/api\/signup"/);
    expect(SRC).toMatch(/method:\s*"POST"/);
    expect(SRC).toMatch(/source:\s*"landing-v1"/);
    expect(SRC).toMatch(/Content-Type/);
  });

  it("handles all three CTO response branches (queued, duplicate, error)", () => {
    expect(SRC).toMatch(/data\.status === "queued"/);
    expect(SRC).toMatch(/data\.status === "duplicate"/);
    expect(SRC).toMatch(/Something went wrong/);
  });

  it("renders the hero copy, the 9-step pipeline list, the features grid, and a signup form", () => {
    expect(SRC).toMatch(/An entire engineering team/);
    expect(SRC).toMatch(/Powered by AI/);
    expect(SRC).toMatch(/From idea to running code in 9 steps/);
    expect(SRC).toMatch(/Join the early access list/);
    expect(SRC).toMatch(/A real org, not a single chat window/);
    expect(SRC).toMatch(/<input[\s\S]*?type="email"/);
  });

  it("uses Tailwind utility classes (no inline style attributes)", () => {
    expect(SRC).toMatch(/className=/);
    expect(SRC).not.toMatch(/style=\{\{/);
  });

  it("declares 9 pipeline steps in PIPELINE_STEPS", () => {
    const matches = SRC.match(/label:\s*"\d{2} →/g);
    expect(matches?.length).toBe(9);
  });

  it("escapes apostrophes per React's no-unescaped-entities rule", () => {
    // The form's hint text uses we&apos;re / we&apos;ll, not raw apostrophes.
    // Raw apostrophes in JSX text would trip the lint rule on next build.
    expect(SRC).toMatch(/We&apos;re onboarding/);
    expect(SRC).toMatch(/We&apos;ll only use your email/);
  });
});
